const issue = $input.all()[0]?.json || {};
const title = (issue.title || '').toLowerCase();
let label = 'triage';
if (title.includes('bug') || title.includes('error') || title.includes('broken')) label = 'bug';
else if (title.includes('feature') || title.includes('request') || title.includes('enhance')) label = 'enhancement';
else if (title.includes('docs') || title.includes('documentation')) label = 'documentation';
return [{ json: { ...issue, suggestedLabel: label } }];
